use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Account {
    pub balance: u64,
    pub nonce: u64,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Transfer {
    pub from: String,
    pub to: String,
    pub amount: u64,
    pub fee: u64,
    pub nonce: u64,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum LedgerError {
    MissingSender,
    BadNonce,
    InsufficientFunds,
    ArithmeticOverflow,
}

pub fn stage_ledger_transfer(
    accounts: &mut HashMap<String, Account>,
    fees: &mut u64,
    transfer: &Transfer,
) -> Result<(), LedgerError> {
    let sender = accounts
        .get(&transfer.from)
        .ok_or(LedgerError::MissingSender)?;
    if sender.nonce != transfer.nonce {
        return Err(LedgerError::BadNonce);
    }

    let total_debit = transfer
        .amount
        .checked_add(transfer.fee)
        .ok_or(LedgerError::ArithmeticOverflow)?;
    let sender_balance = sender
        .balance
        .checked_sub(total_debit)
        .ok_or(LedgerError::InsufficientFunds)?;
    let sender_nonce = sender
        .nonce
        .checked_add(1)
        .ok_or(LedgerError::ArithmeticOverflow)?;

    let mut next_accounts = accounts.clone();
    next_accounts.insert(
        transfer.from.clone(),
        Account {
            balance: sender_balance,
            nonce: sender_nonce,
        },
    );
    let recipient = next_accounts.entry(transfer.to.clone()).or_insert(Account {
        balance: 0,
        nonce: 0,
    });
    recipient.balance = recipient
        .balance
        .checked_add(transfer.amount)
        .ok_or(LedgerError::ArithmeticOverflow)?;
    let next_fees = fees
        .checked_add(transfer.fee)
        .ok_or(LedgerError::ArithmeticOverflow)?;

    *accounts = next_accounts;
    *fees = next_fees;
    Ok(())
}

use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Account {
    pub balance: u64,
    pub nonce: u64,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Transaction {
    pub from: String,
    pub to: String,
    pub amount: u64,
    pub fee: u64,
    pub nonce: u64,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum LedgerError {
    MissingSender,
    BadNonce,
    InsufficientFunds,
    ArithmeticOverflow,
}

pub fn apply_checked_transaction(
    accounts: &mut HashMap<String, Account>,
    fee_sink: &mut u64,
    tx: &Transaction,
) -> Result<(), LedgerError> {
    let sender = accounts.get(&tx.from).ok_or(LedgerError::MissingSender)?;
    if sender.nonce != tx.nonce {
        return Err(LedgerError::BadNonce);
    }

    let total_debit = tx
        .amount
        .checked_add(tx.fee)
        .ok_or(LedgerError::ArithmeticOverflow)?;
    let next_sender_balance = sender
        .balance
        .checked_sub(total_debit)
        .ok_or(LedgerError::InsufficientFunds)?;
    let next_sender_nonce = sender
        .nonce
        .checked_add(1)
        .ok_or(LedgerError::ArithmeticOverflow)?;

    let mut next_accounts = accounts.clone();
    next_accounts.insert(
        tx.from.clone(),
        Account {
            balance: next_sender_balance,
            nonce: next_sender_nonce,
        },
    );

    let recipient = next_accounts.entry(tx.to.clone()).or_insert(Account {
        balance: 0,
        nonce: 0,
    });
    recipient.balance = recipient
        .balance
        .checked_add(tx.amount)
        .ok_or(LedgerError::ArithmeticOverflow)?;

    let next_fee_sink = fee_sink
        .checked_add(tx.fee)
        .ok_or(LedgerError::ArithmeticOverflow)?;
    *accounts = next_accounts;
    *fee_sink = next_fee_sink;
    Ok(())
}
